import{H as e,at as t,bt as n,et as r,it as i,ot as a,rt as o,wt as s}from"./chunks/framework.Bz2nrw0B.js";var c=JSON.parse(`{"title":"Drone 环境变量","description":"Drone CI 服务端全部环境变量参考手册，涵盖数据库配置、OAuth 认证、日志格式、S3 存储和 TLS 证书等核心参数的中文翻译说明","frontmatter":{"title":"Drone 环境变量","category":["Drone"],"tag":["环境变量","服务端配置","参考手册"],"description":"Drone CI 服务端全部环境变量参考手册，涵盖数据库配置、OAuth 认证、日志格式、S3 存储和 TLS 证书等核心参数的中文翻译说明","date":"2022-07-25T15:33:28.000Z","updated":"2022-07-25T15:33:28.000Z","cover":"https://docs.drone.io/logo.svg"},"headers":[],"relativePath":"articles/devops/ci-cd/drone/drone-env.md","filePath":"articles/devops/ci-cd/drone/drone-env.md"}`),l={name:`articles/devops/ci-cd/drone/drone-env.md`};function u(e,c,l,u,d,f){let p=s(`SmallCard`);return n(),o(`div`,null,[c[0]||=r(`h2`,{id:`参考资料`,tabindex:`-1`},[t(`参考资料 `),r(`a`,{class:`header-anchor`,href:`#参考资料`,"aria-label":`Permalink to “参考资料”`},`​`)],-1),a(p,{cards:[{title:`Reference Index of server configuration settings`,desc:`Drone is a self-service Continuous Integration platform for busy development teams.`,logo:`https://docs.drone.io/logo.svg`,link:`https://docs.drone.io/server/reference/`}]}),c[1]||=i('<h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to “注意事项”">​</a></h2><ol><li>文档翻译为<a href="https://www.deepl.com" target="_blank" rel="noreferrer">Deepl</a>机翻。</li><li>默认值：无，仅表示翻译过程中并未直接指出该环境变量的值是什么。</li><li>此翻译，仅供参数。</li><li>docker镜像版本为<code>drone/drone:2</code>下环境变量解释。</li></ol><h2 id="环境变量" tabindex="-1">环境变量 <a class="header-anchor" href="#环境变量" aria-label="Permalink to “环境变量”">​</a></h2><ol><li><p>DRONE_BITBUCKET_CLIENT_ID</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_BITBUCKET_CLIENT_ID</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">字符串值。配置Bitbucket OAuth客户端ID。这是用来代表Drone用户授权访问Bitbucket的。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_BITBUCKET_CLIENT_ID=05136e57d80189bef462</td></tr></tbody></table></li><li><p>DRONE_BITBUCKET_CLIENT_SECRET</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_BITBUCKET_CLIENT_SECRET</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">字符串值。配置Bitbucket OAuth客户端秘密。这是用来代表Drone用户授权访问Bitbucket的。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_BITBUCKET_CLIENT_SECRET=7c229228a77d2cbddaa61ddc78d45e</td></tr></tbody></table></li><li><p>DRONE_BITBUCKET_DEBUG</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_BITBUCKET_DEBUG</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的布尔值。配置Bitbucket认证的详细跟踪记录。这应该被用来解决安装Drone服务器时的登录问题。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">false</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_BITBUCKET_DEBUG=false</td></tr></tbody></table></li><li><p>DRONE_CLEANUP_DEADLINE_PENDING</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_CLEANUP_DEADLINE_PENDING</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的持续时间值。配置待处理作业被收割机杀死的时间间隔。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">24h</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_CLEANUP_DEADLINE_PENDING=24h</td></tr></tbody></table></li><li><p>DRONE_CLEANUP_DEADLINE_RUNNING</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_CLEANUP_DEADLINE_RUNNING</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的持续时间值。配置运行中的作业被收割机杀死的时间间隔。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">24h</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_CLEANUP_DEADLINE_RUNNING=24h</td></tr></tbody></table></li><li><p>DRONE_CLEANUP_DISABLED</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_CLEANUP_DISABLED</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">布尔值禁用收割机。收割机发现并杀死永久停留在挂起或运行状态的僵尸作业。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">false</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_CLEANUP_DISABLED=true/DRONE_CLEANUP_DISABLED=false</td></tr></tbody></table></li><li><p>DRONE_CLEANUP_INTERVAL</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_CLEANUP_INTERVAL</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的持续时间值。配置运行收割机的时间间隔。默认情况下，收割机每隔24小时就会发现并杀死那些永久停留在待定或运行状态的僵尸作业。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">24h</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_CLEANUP_INTERVAL=24h/DRONE_CLEANUP_INTERVAL=60m</td></tr></tbody></table></li><li><p>DRONE_CONVERT_PLUGIN_ENDPOINT</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_CONVERT_PLUGIN_ENDPOINT</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">字符串值配置转换插件的端点，用于自动转换或修改配置文件。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_CONVERT_PLUGIN_ENDPOINT=<code>http://hostname.com:3000</code></td></tr></tbody></table></li><li><p>DRONE_CONVERT_PLUGIN_EXTENSION</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_CONVERT_PLUGIN_EXTENSION</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">字符串值配置应与转换插件一起使用的文件扩展名。此配置参数用于减少不会转换的文件类型的转换插件的不必要流量。它是完全可选的。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_CONVERT_PLUGIN_EXTENSION=.star</td></tr></tbody></table></li><li><p>DRONE_CONVERT_PLUGIN_SECRET</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_CONVERT_PLUGIN_SECRET</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">用于创建http-signature的共享密钥。转换插件使用共享密钥来验证请求的真实性。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_CONVERT_PLUGIN_SECRET=correct-horse-battery-staple</td></tr></tbody></table></li><li><p>DRONE_CONVERT_PLUGIN_SKIP_VERIFY</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_CONVERT_PLUGIN_SKIP_VERIFY</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">布尔值在建立与远程转换插件的连接时禁用TLS验证。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">false</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_CONVERT_PLUGIN_SKIP_VERIFY=false</td></tr></tbody></table></li><li><p>DRONE_COOKIE_SECRET</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_COOKIE_SECRET</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的字符串值。配置用于签署认证cookies的秘钥。如果不设置，每次启动服务器时都会生成一个随机值。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_COOKIE_SECRET=correct-horse-battery-staple</td></tr></tbody></table></li><li><p>DRONE_COOKIE_TIMEOUT</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_COOKIE_TIMEOUT</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的期限值。配置认证cookie的过期时间。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">720h</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_COOKIE_TIMEOUT=720h</td></tr></tbody></table></li><li><p>DRONE_CRON_DISABLED</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_CRON_DISABLED</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">布尔值，禁用cron调度程序。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">false</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_CRON_DISABLED=false</td></tr></tbody></table></li><li><p>DRONE_CRON_INTERVAL</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_CRON_INTERVAL</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的持续时间值。配置运行cron调度程序的时间间隔。cron调度器并不意味着准确，默认情况下，每隔一小时就会对待处理的工作进行批处理。<strong>请注意，即使你减少了cron的间隔时间，你也不应该期望有高水平的准确性。我们的主要设计目标是创建一个安全、高效的cron调度器，防止用户对系统进行超载；这是以牺牲准确性为代价的。</strong></td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">1h</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_CRON_INTERVAL=1h/DRONE_CRON_INTERVAL=5m</td></tr></tbody></table></li><li><p>DRONE_DATABASE_DATASOURCE</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_DATABASE_DATASOURCE</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的字符串值。配置数据库连接字符串。默认值是嵌入式sqlite数据库文件的路径。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">/data/database.sqlite</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">mysql: DRONE_DATABASE_DATASOURCE=root:password@tcp(1.2.3.4:3306)/drone?parseTime=true postgres: DRONE_DATABASE_DATASOURCE=postgres://root:password@1.2.3.4:5432/postgres?sslmode=disable</td></tr></tbody></table></li><li><p>DRONE_DATABASE_DRIVER</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_DATABASE_DRIVER</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的字符串值。配置数据库驱动程序的名称。默认值是sqlite3驱动。替代驱动是postgres和mysql。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">sqlite3</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_DATABASE_DRIVER=mysql/DRONE_DATABASE_DRIVER=postgres</td></tr></tbody></table></li><li><p>DRONE_DATABASE_MAX_CONNECTIONS</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_DATABASE_MAX_CONNECTIONS</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的数字值。设置Drone的最大开放DB连接数。默认设置为0，必须在系统首次使用前进行配置。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">0</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_DATABASE_MAX_CONNECTIONS=45</td></tr></tbody></table></li><li><p>DRONE_DATABASE_SECRET</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_DATABASE_SECRET</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的字符串值。配置用于加密数据库中秘密的秘密密钥。加密在默认情况下是禁用的，必须在系统首次使用前进行配置。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">默认禁用</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_DATABASE_SECRET=7c229228a77d2cbddaa61ddc78d45e</td></tr></tbody></table></li><li><p>DRONE_GIT_ALWAYS_AUTH</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_GIT_ALWAYS_AUTH</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的布尔值。将 Drone 配置为在克隆公共存储库时进行身份验证。仅当您的源代码管理系统（例如 GitHub Enterprise）启用了私有模式时才需要这样做。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">false</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_GIT_ALWAYS_AUTH=false</td></tr></tbody></table></li><li><p>DRONE_GIT_PASSWORD</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_GIT_PASSWORD</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的字符串值。覆盖默认的git用户名和密码，用于验证和克隆私有仓库。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_GIT_PASSWORD=7c229228a77d2cbddaa61ddc78d45e</td></tr></tbody></table></li><li><p>DRONE_GIT_USERNAME</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_GIT_USERNAME</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的字符串值。覆盖默认的git用户名和密码，用于验证和克隆私有仓库。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_GIT_USERNAME=x-oauth-token</td></tr></tbody></table></li><li><p>DRONE_GITEA_CLIENT_ID</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_GITEA_CLIENT_ID</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">字符串值用于配置Gitea OAuth客户端ID。这是用来代表Drone用户授权访问Gitea的。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_GITEA_CLIENT_ID=05136e57d80189bef462</td></tr></tbody></table></li><li><p>DRONE_GITEA_CLIENT_SECRET</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_GITEA_CLIENT_SECRET</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">字符串值配置了Gitea OAuth客户端的秘密。这是用来代表Drone用户授权访问Gitea的。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_GITEA_CLIENT_SECRET=7c229228a77d2cbddaa61ddc78d45e</td></tr></tbody></table></li><li><p>DRONE_GITEA_SERVER</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_GITEA_SERVER</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">字符串值配置 Gitea 服务器地址。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_GITEA_SERVER=<code>https://try.gitea.io</code></td></tr></tbody></table></li><li><p>DRONE_GITEA_SKIP_VERIFY</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_GITEA_SKIP_VERIFY</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">布尔值在建立与远程 Gitea 服务器的连接时禁用 tls 验证。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">false</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_GITEA_SKIP_VERIFY=false</td></tr></tbody></table></li><li><p>DRONE_GITEE_REDIRECT_URL</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_GITEE_REDIRECT_URL</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">字符串值配置 Gitee OAuth 授权重定向 url。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">${DRONE_SERVER_PROTO}😕/${DRONE_SERVER_HOST}/login</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_GITEE_REDIRECT_URL=<code>https://drone.domain.com/login</code></td></tr></tbody></table></li><li><p>DRONE_GITEE_SCOPE</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_GITEE_SCOPE</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">字符串值提供以逗号分隔的 OAuth 范围列表。不应修改默认值。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">user_info,projects,pull_requests,hook</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_GITEE_SCOPE=&quot;user_info,projects,pull_requests,hook&quot;</td></tr></tbody></table></li><li><p>DRONE_GITEE_SKIP_VERIFY</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_GITEE_SKIP_VERIFY</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">布尔值在建立与远程 Gitee 服务器的连接时禁用 TLS 验证。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">false</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_GITEE_SKIP_VERIFY=false</td></tr></tbody></table></li><li><p>DRONE_GITHUB_CLIENT_ID</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_GITHUB_CLIENT_ID</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">字符串值用于配置GitHub OAuth客户端ID。这是用来代表Drone用户授权访问GitHub的。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_GITHUB_CLIENT_ID=05136e57d80189bef462</td></tr></tbody></table></li><li><p>DRONE_GITHUB_CLIENT_SECRET</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_GITHUB_CLIENT_SECRET</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">字符串值配置了GitHub oauth客户端的秘密。这是用来代表Drone用户授权访问GitHub的。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_GITHUB_CLIENT_SECRET=7c229228a77d2cbddaa61ddc78d45e</td></tr></tbody></table></li><li><p>DRONE_GITHUB_SCOPE</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_GITHUB_SCOPE</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">字符串值提供了一个以逗号分隔的OAuth作用域列表。默认值不应该被修改。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">repo,repo:status,user:email,read:org</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_GITHUB_SCOPE=repo,repo:status,user:email,read:org</td></tr></tbody></table></li><li><p>DRONE_GITHUB_SERVER</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_GITHUB_SERVER</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">字符串值用于配置GitHub服务器地址。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;"><code>https://github.com</code></td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_GITHUB_SERVER=<code>https://github.com</code></td></tr></tbody></table></li><li><p>DRONE_GITHUB_SKIP_VERIFY</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_GITHUB_SKIP_VERIFY</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">布尔值在与远程GitHub服务器建立连接时禁用TLS验证。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">false</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_GITHUB_SKIP_VERIFY=false</td></tr></tbody></table></li><li><p>DRONE_GITLAB_CLIENT_ID</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_GITLAB_CLIENT_ID</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">字符串值用于配置GitLab OAuth客户端ID。这是用来代表Drone用户授权访问GitLab的。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_GITLAB_CLIENT_ID=05136e57d80189bef462</td></tr></tbody></table></li><li><p>DRONE_GITLAB_CLIENT_SECRET</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_GITLAB_CLIENT_SECRET</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">字符串值用于配置GitLab OAuth客户端秘密。这是用来代表Drone用户授权访问GitLab的。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_GITLAB_CLIENT_SECRET=7c229228a77d2cbddaa61ddc78d45e</td></tr></tbody></table></li><li><p>DRONE_GITLAB_SERVER</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_GITLAB_SERVER</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">字符串值用于配置GitLab服务器地址。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;"><code>https://gitlab.com</code></td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_GITLAB_SERVER=<code>https://gitlab.com</code></td></tr></tbody></table></li><li><p>DRONE_GITLAB_SKIP_VERIFY</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_GITLAB_SKIP_VERIFY</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">布尔值在与远程GitLab服务器建立连接时禁用TLS验证。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">false</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_GITLAB_SKIP_VERIFY=false</td></tr></tbody></table></li><li><p>DRONE_GOGS_SERVER</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_GOGS_SERVER</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">字符串值配置Gogs服务器地址。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_GOGS_SERVER=<code>https://try.gogs.io</code></td></tr></tbody></table></li><li><p>DRONE_GOGS_SKIP_VERIFY</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_GOGS_SKIP_VERIFY</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">布尔值用于配置与远程Gogs服务器建立连接时的TLS验证。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">false</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_GOGS_SKIP_VERIFY=false</td></tr></tbody></table></li><li><p>DRONE_JSONNET_ENABLED</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_JSONNET_ENABLED</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">布尔值用于配置Drone自动将以<code>.jsonnet</code>结尾的配置文件转换为yaml。这在默认情况下是禁用的，只应在受信任的环境中启用。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">true</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_JSONNET_ENABLED=true</td></tr></tbody></table></li><li><p>DRONE_LICENSE</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_LICENSE</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的字符串值提供Drone企业版许可密钥的文件路径。这用于解锁Drone企业版。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_LICENSE=/etc/drone.key ；如果你在Docker容器中运行Drone服务器，你将需要把许可证密钥挂载为一个卷。$ docker run --volume=/path/on/host/drone.key:/etc/drone.key;如果你使用Docker Compose或Kubernetes运行Drone服务器，或者你使用Yaml配置了Drone，你可以将许可证密钥作为环境变量提供给服务器。DRONE_LICENSE: <code>-----BEGIN LICENSE KEY-----</code> Thjh7sTA1VDE4OjM2tpmQQZCyRd43M1ODI1OVoiLCJkYXQiSukU/Y -----END LICENSE KEY-----</td></tr></tbody></table></li><li><p>DRONE_LOGS_COLOR</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_LOGS_COLOR</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">启用日志的彩色格式化；与漂亮的打印日志一起使用。这个配置参数的类型是布尔值，是可选的。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_LOGS_COLOR=false/true</td></tr></tbody></table></li><li><p>DRONE_LOGS_DEBUG</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_LOGS_DEBUG</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">启用调试日志。这个配置参数的类型是布尔值，是可选的。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_LOGS_DEBUG=true/false</td></tr></tbody></table></li><li><p>DRONE_LOGS_PRETTY</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_LOGS_PRETTY</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">启用人类可读的日志，作为默认json格式的替代。这个配置参数的类型是布尔值，是可选的。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_LOGS_PRETTY=true/false</td></tr></tbody></table></li><li><p>DRONE_LOGS_TEXT</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_LOGS_TEXT</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">启用人类可读的日志，作为默认json格式的替代。这个配置参数的类型是布尔值，是可选的。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_LOGS_TEXT=true/false</td></tr></tbody></table></li><li><p>DRONE_LOGS_TRACE</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_LOGS_TRACE</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">启用跟踪记录。这个配置参数的类型是布尔值，是可选的。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_LOGS_TRACE=true/false</td></tr></tbody></table></li><li><p>DRONE_PROMETHEUS_ANONYMOUS_ACCESS</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_PROMETHEUS_ANONYMOUS_ACCESS</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">布尔值用于配置Prometheus度量衡端点允许匿名访问。这在默认情况下是禁用的，需要认证令牌来访问度量衡端点。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">false</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_PROMETHEUS_ANONYMOUS_ACCESS=false</td></tr></tbody></table></li><li><p>DRONE_REGISTRATION_CLOSED</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_REGISTRATION_CLOSED</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">布尔值禁用开放注册。如果启用，系统管理员必须在用户登录前创建用户账户。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">false</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_REGISTRATION_CLOSED=false</td></tr></tbody></table></li><li><p>DRONE_REPOSITORY_FILTER</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_REPOSITORY_FILTER</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的逗号分隔的账户列表，用于限制源码控制系统和Drone之间同步的存储库。请注意，这个变量必须在你第一次登录之前设置。在已经验证并同步了你的账户后设置这个变量没有任何效果。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_REPOSITORY_FILTER=octocat,spacheghost</td></tr></tbody></table></li><li><p>DRONE_RPC_SECRET</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_RPC_SECRET</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">要求的字面价值提供Drone共享秘密。这用于验证与服务器的RPC连接。服务器和运行者必须提供相同的秘密值。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_RPC_SECRET=correct-horse-batter-staple</td></tr></tbody></table></li><li><p>DRONE_S3_BUCKET</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_S3_BUCKET</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的字符串值，配置S3桶的名称</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_S3_BUCKET=my-bucket</td></tr></tbody></table></li><li><p>DRONE_S3_ENDPOINT</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_S3_ENDPOINT</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的字符串值用于配置S3端点。通常用于与S3兼容的服务，如Minio。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_S3_ENDPOINT=<code>https://play.min.io</code></td></tr></tbody></table></li><li><p>DRONE_S3_PATH_STYLE</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_S3_PATH_STYLE</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的布尔值将S3客户端配置为使用路径风格。这通常用于与S3兼容的服务，如Minio。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_S3_PATH_STYLE=false</td></tr></tbody></table></li><li><p>DRONE_S3_PREFIX</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_S3_PREFIX</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的字符串值，配置S3客户端将日志文件存储在一个桶的子目录。如果没有设置，日志文件将存储在桶的根目录中。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_S3_PREFIX=some/path</td></tr></tbody></table></li><li><p>DRONE_SERVER_HOST</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_SERVER_HOST</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">必要的字符串值配置面向用户的主机名。这个值被用来创建webhooks和重定向url。它对服务流量没有实际影响。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_SERVER_HOST=drone.company.com</td></tr></tbody></table></li><li><p>DRONE_SERVER_PROTO</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_SERVER_PROTO</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">必要的字符串值配置面向用户的协议。这个值用于创建webhooks和重定向url。它对服务流量没有实际影响。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_SERVER_PROTO=https</td></tr></tbody></table></li><li><p>DRONE_SERVER_PROXY_HOST</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_SERVER_PROXY_HOST</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的字符串值，用于创建通过另一个代理服务器路由的webhooks。这个设置的目标用例是当你的服务器在防火墙后面，你需要GitHub的webhooks通过公共代理路由。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_SERVER_PROXY_HOST=external.drone.company.com</td></tr></tbody></table></li><li><p>DRONE_SERVER_PROXY_PROTO</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_SERVER_PROXY_PROTO</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的字符串值，用于创建通过另一个代理服务器路由的webhooks。这个设置的目标用例是当你的服务器在防火墙后面，你需要GitHub的webhooks通过公共代理路由。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_SERVER_PROXY_PROTO=https</td></tr></tbody></table></li><li><p>DRONE_STARLARK_ENABLED</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_STARLARK_ENABLED</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">布尔值用于配置Drone自动执行以.star结尾的文件，以提供你的管道配置。这在默认情况下是禁用的。该功能需要Drone服务器版本1.10.0或更高。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">false</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_STARLARK_ENABLED=true</td></tr></tbody></table></li><li><p>DRONE_STARLARK_STEP_LIMIT</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_STARLARK_STEP_LIMIT</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">整数值。设置starlark配置可以产生的最大步骤数。默认是50000。该功能需要Drone服务器2.2.1版或更高版本。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">50000</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_STARLARK_STEP_LIMIT=100000</td></tr></tbody></table></li><li><p>DRONE_STASH_CONSUMER_KEY</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_STASH_CONSUMER_KEY</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">字符串值配置你的Bitbucket服务器消费者密钥</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_STASH_CONSUMER_KEY=OauthKey</td></tr></tbody></table></li><li><p>DRONE_STASH_PRIVATE_KEY</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_STASH_PRIVATE_KEY</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">字符串值用于配置Bitbucket服务器私钥文件的路径。注意，这个文件也需要作为一个卷装入Drone服务器容器中。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_STASH_PRIVATE_KEY=/etc/bitbucket/key.pem</td></tr></tbody></table></li><li><p>DRONE_STASH_SERVER</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_STASH_SERVER</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">字符串值配置Bitbucket服务器地址。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_STASH_SERVER=<code>https://bitbucket.company.com</code></td></tr></tbody></table></li><li><p>DRONE_STASH_SKIP_VERIFY</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_STASH_SKIP_VERIFY</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">布尔值在与远程Bitbucket服务器建立连接时禁用TLS验证。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">false</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_STASH_SKIP_VERIFY=false</td></tr></tbody></table></li><li><p>DRONE_STATUS_DISABLED</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_STATUS_DISABLED</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">布尔值禁止系统使用状态API向源控制管理系统传递构建状态。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">false</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_STATUS_DISABLED=true</td></tr></tbody></table></li><li><p>DRONE_STATUS_NAME</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_STATUS_NAME</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">字符串值配置用于向源控制管理系统传达构建状态的状态名称。默认值是<code>continuous-integration/drone</code>。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;"><code>continuous-integration/drone</code></td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_STATUS_NAME=continuous-integration/drone</td></tr></tbody></table></li><li><p>DRONE_TLS_AUTOCERT</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_TLS_AUTOCERT</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">使用Lets Encrypt自动生成一个SSL证书，并配置服务器接受HTTPS请求。这个配置参数的类型是布尔值，是可选的，默认情况下是禁用的。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">false</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_TLS_AUTOCERT=true</td></tr></tbody></table></li><li><p>DRONE_TLS_CERT</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_TLS_CERT</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">服务器用于接受HTTPS请求的SSL证书的路径。这个配置参数的类型是字符串，是可选的。<strong>请注意，证书文件应该是服务器的证书、任何中介机构和证书颁发机构的证书的串联。</strong></td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_TLS_CERT=/path/to/cert.pem</td></tr></tbody></table></li><li><p>DRONE_TLS_KEY</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_TLS_KEY</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">服务器用于接受HTTPS请求的SSL证书密钥的路径。这个配置参数的类型是字符串，是可选的。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_TLS_KEY=/path/to/key.pem</td></tr></tbody></table></li><li><p>DRONE_USER_CREATE</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_USER_CREATE</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的用户账户，应该在启动时创建。这应该是用来给系统播种的一个管理账户。它可以是一个真实的账户（即一个真实的GitHub用户），也可以是一个机器账户。 为机器账户提供一个令牌是必须的，而且必须是32字节。你可以用以下命令生成一个随机的32字节的令牌。<code>openssl rand -hex 16</code> 55f24eb3d61ef6ac5e83d550178638dc</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_USER_CREATE=username:octocat,machine:false,admin:true,token:55f24eb3d61ef6ac5e83d550178638dc</td></tr></tbody></table></li><li><p>DRONE_USER_FILTER</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_USER_FILTER</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的逗号分隔的账户列表。注册仅限于此列表中的用户，或属于此列表中的组织成员的用户。<strong>如果一个用户试图注册，而他们不是一个命名的用户，也不是一个命名的组织的成员，他们将收到以下错误。 登录失败。用户必须是一个被批准的组织的成员。</strong></td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_USER_FILTER=octocat,spacheghost,github</td></tr></tbody></table></li><li><p>DRONE_VALIDATE_PLUGIN_ENDPOINT</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_VALIDATE_PLUGIN_ENDPOINT</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">字符串值配置验证插件的端点，用于为你的管道配置强制执行自定义提示规则。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_VALIDATE_PLUGIN_ENDPOINT=<code>http://hostname.com:3000</code></td></tr></tbody></table></li><li><p>DRONE_VALIDATE_PLUGIN_SECRET</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_VALIDATE_PLUGIN_SECRET</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">用于创建http-signature的共享秘密。验证插件使用该共享秘密来验证请求的真实性。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_VALIDATE_PLUGIN_SECRET=correct-horse-battery-staple</td></tr></tbody></table></li><li><p>DRONE_VALIDATE_PLUGIN_SKIP_VERIFY</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_VALIDATE_PLUGIN_SKIP_VERIFY</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">布尔值在建立与远程验证插件的连接时禁用TLS验证。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">false</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_VALIDATE_PLUGIN_SKIP_VERIFY=false</td></tr></tbody></table></li><li><p>DRONE_WEBHOOK_ENDPOINT</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_WEBHOOK_ENDPOINT</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">字符串值配置了一个以逗号分隔的webhook端点列表，全局系统事件将被传递到该列表。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_WEBHOOK_ENDPOINT=<code>http://postb.in/b/cajf7cIU</code></td></tr></tbody></table></li><li><p>DRONE_WEBHOOK_EVENTS</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_WEBHOOK_EVENTS</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的字符串值提供了一个以逗号分隔的触发webhooks的事件和行动的列表。如果不设置，所有的事件和动作都会触发webhooks。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">按事件类型限制: DRONE_WEBHOOK_EVENTS=user,build 按事件类型和行动限制 : DRONE_WEBHOOK_EVENTS=user:created,repo 可用的事件列表: user:created user:updated user:deleted repo:enabled repo:disabled repo:updated build:created build:updated</td></tr></tbody></table></li><li><p>DRONE_WEBHOOK_SECRET</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_WEBHOOK_SECRET</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">用于创建http-signature的共享秘密。webhook接收者可以使用共享秘密来验证请求的真实性。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_WEBHOOK_SECRET=correct-horse-battery-staple</td></tr></tbody></table></li><li><p>DRONE_WEBHOOK_SKIP_VERIFY</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_WEBHOOK_SKIP_VERIFY</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">布尔值在建立与远程webhook地址的连接时禁用TLS验证。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">false</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_WEBHOOK_SKIP_VERIFY=false</td></tr></tbody></table></li></ol>',4)])}var d=e(l,[[`render`,u]]);export{c as __pageData,d as default};